import{_ as s,c as a,o as l,a as n}from"./app.204b65b3.js";const d=JSON.parse('{"title":"11.缓存","description":"","frontmatter":{},"headers":[{"level":2,"title":"1.简介","slug":"_1-简介","link":"#_1-简介","children":[]},{"level":2,"title":"2.MyBatis 缓存","slug":"_2-mybatis-缓存","link":"#_2-mybatis-缓存","children":[]},{"level":2,"title":"3.一级缓存","slug":"_3-一级缓存","link":"#_3-一级缓存","children":[]},{"level":2,"title":"4.二级缓存","slug":"_4-二级缓存","link":"#_4-二级缓存","children":[]},{"level":2,"title":"5.缓存失效的情况","slug":"_5-缓存失效的情况","link":"#_5-缓存失效的情况","children":[]},{"level":2,"title":"6.二级缓存的使用","slug":"_6-二级缓存的使用","link":"#_6-二级缓存的使用","children":[]},{"level":2,"title":"7.缓存原理图","slug":"_7-缓存原理图","link":"#_7-缓存原理图","children":[]},{"level":2,"title":"8.MyBatis 整合 ehcache","slug":"_8-mybatis-整合-ehcache","link":"#_8-mybatis-整合-ehcache","children":[]}],"relativePath":"articles/02-后端/Java/04-MyBatis/11.缓存.md"}'),e={name:"articles/02-后端/Java/04-MyBatis/11.缓存.md"},p=n(`<h1 id="_11-缓存" tabindex="-1">11.缓存 <a class="header-anchor" href="#_11-缓存" aria-hidden="true">#</a></h1><h2 id="_1-简介" tabindex="-1">1.简介 <a class="header-anchor" href="#_1-简介" aria-hidden="true">#</a></h2><ol><li>什么是缓存 [ Cache ] ? <ul><li>存在内存中的临时数据</li><li>将用户经常查询的数据放在缓存（内存）中，用户查询数据就不用从数据库中查询，从缓存中查询，从而提高查询小龙，解决了高并发系统的性能问题。</li></ul></li><li>为什么使用缓存 <ul><li>减少和数据库的交互次数，减少系统开销，提高系统效率</li></ul></li><li>什么样的数据能使用缓存？ <ul><li>经常查询并且不经常改变的数据</li></ul></li></ol><h2 id="_2-mybatis-缓存" tabindex="-1">2.MyBatis 缓存 <a class="header-anchor" href="#_2-mybatis-缓存" aria-hidden="true">#</a></h2><ul><li>MyBatis 包含一个非常强大的查询缓存特性，它可以非常方便地定制和配置缓存。缓存可以极大的提升查询效率。</li><li>MyBatis 系统中默认定义了两个缓存：<strong>一级缓存</strong>和<strong>二级缓存</strong><ul><li>默认情况下，只有一级缓存开启。（SqlSession 级别的缓存，也称为本地缓存）</li><li>二级缓存需要手动开启和配置，他是基于 namespace 级别的缓存。</li><li>为了提高拓展性，MyBatis 定义了缓存接口 Cache。我们可以通过实现 Cache 接口来定义二级缓存</li></ul></li></ul><h2 id="_3-一级缓存" tabindex="-1">3.一级缓存 <a class="header-anchor" href="#_3-一级缓存" aria-hidden="true">#</a></h2><ul><li>一级缓存也叫本地缓存 <ul><li>与数据库同一次会话期间查询到的数据会放在本地缓存中</li><li>以后如果需要获取相同的数据，直接从缓存中拿，没必要再取查询数据库</li></ul></li></ul><h2 id="_4-二级缓存" tabindex="-1">4.二级缓存 <a class="header-anchor" href="#_4-二级缓存" aria-hidden="true">#</a></h2><ul><li>二级缓存也叫全局缓存，一级缓存作用域太低了，所有诞生了二级缓存</li><li>基于 namespace 级别的缓存，一个名称空间对应一个二级缓存</li><li>工作机制 <ul><li>一个会话查询一条数据，这个数据会被放到当前会话的一级缓存中；</li><li>如果当前会话关闭了，这个会话对应的一级缓存就没了；但是我们开启了二级缓存，会话关闭了，一级缓存中的数据会被保存到二级缓存中；</li><li>新的会话查询信息，就可以从二级缓存中获取内容</li><li>不同的 mapper 查出的数据会放再自己对应的缓存中</li></ul></li></ul><h2 id="_5-缓存失效的情况" tabindex="-1">5.缓存失效的情况 <a class="header-anchor" href="#_5-缓存失效的情况" aria-hidden="true">#</a></h2><ul><li>不同的 SqlSession 对应不同的一级缓存</li><li>同一个 SqlSession 但是查询条件不同</li><li>一个 SqlSession 两次查询期间执行了任何一次增删改操作</li><li>同一个 SqlSession 两次查询期间手动清空了缓存</li></ul><h2 id="_6-二级缓存的使用" tabindex="-1">6.二级缓存的使用 <a class="header-anchor" href="#_6-二级缓存的使用" aria-hidden="true">#</a></h2><ul><li>开启全局缓存</li></ul><div class="language-xml"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">&lt;!-- 开启二级缓存总开关 --&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">setting</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">name</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">cacheEnabled</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">true</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">/&gt;</span></span>
<span class="line"></span></code></pre></div><ul><li>开启 Mapper.xml 的二级缓存</li></ul><div class="language-xml"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">&lt;!--</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">	开启mapper下的namespace的二级缓存,</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">	cache标签中的所有属性都是可选的</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"> --&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">cache</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">eviction</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">FIFO</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">flushInterval</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">60000</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">size</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">512</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">readOnly</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">true</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">/&gt;</span></span>
<span class="line"></span></code></pre></div><ul><li>cache 标签的属性</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">eviction: 缓存的回收策略, 默认的是 LRU</span></span>
<span class="line"><span style="color:#A6ACCD;"> LRU – 最近最少使用的:移除最长时间不被使用的对象。</span></span>
<span class="line"><span style="color:#A6ACCD;"> FIFO – 先进先出:按对象进入缓存的顺序来移除它们。</span></span>
<span class="line"><span style="color:#A6ACCD;"> SOFT – 软引用:移除基于垃圾回收器状态和软引用规则的对象。</span></span>
<span class="line"><span style="color:#A6ACCD;"> WEAK – 弱引用:更积极地移除基于垃圾收集器状态和弱引用规则的对象。</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">flushInterval: 缓存刷新间隔, 默认不清空</span></span>
<span class="line"><span style="color:#A6ACCD;"> 缓存多长时间清空一次, 设置一个毫秒值</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">readOnly: 是否只读, 默认false</span></span>
<span class="line"><span style="color:#A6ACCD;"> true: 只读, mybatis认为所有从缓存中获取数据的操作都是只读操作, 不会修改数据。mybatis为了加快获取速度, 直接就会将数据在缓存中的引用交给用户。不安全, 速度快</span></span>
<span class="line"><span style="color:#A6ACCD;"> false: 非只读, mybatis觉得获取的数据可能会被修改。mybatis会利用序列化&amp;反序列的技术克隆一份新的数据给你。安全, 速度慢。</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">size: 缓存存放多少元素;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">type: 指定自定义缓存的全类名;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><h2 id="_7-缓存原理图" tabindex="-1">7.缓存原理图 <a class="header-anchor" href="#_7-缓存原理图" aria-hidden="true">#</a></h2><p><img src="https://fang-kang.gitee.io/blog-img/mybatis/1.png#id=uZShE&amp;originHeight=402&amp;originWidth=702&amp;originalType=binary&amp;ratio=1&amp;status=done&amp;style=none" alt="" data-fancybox="gallery"></p><h2 id="_8-mybatis-整合-ehcache" tabindex="-1">8.MyBatis 整合 ehcache <a class="header-anchor" href="#_8-mybatis-整合-ehcache" aria-hidden="true">#</a></h2><ol><li>导入第三方缓存 jar 包和与第三方缓存整合的适配包</li></ol><div class="language-xml"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">dependency</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">groupId</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">net.sf.ehcache</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">groupId</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">artifactId</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">ehcache-web</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">artifactId</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">version</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">2.0.4</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">version</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">optional</span><span style="color:#89DDFF;">&gt;</span><span style="color:#A6ACCD;">true</span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">optional</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">dependency</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><ol start="2"><li>mapper.xml 中使用自定义缓存</li></ol><div class="language-xml"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">cache</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">org.mybatis.caches.ehcache.EhcacheCache</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">/&gt;</span></span>
<span class="line"></span></code></pre></div>`,25),t=[p];function o(c,i,r,y,D,F){return l(),a("div",null,t)}const u=s(e,[["render",o]]);export{d as __pageData,u as default};
